    let mut cmd = Command::cargo_bin("caut").unwrap();
    cmd.arg("--version")
        .assert()
        .success()
        .stdout(predicate::str::is_match(r"\d+\.\d+").unwrap());
}

#[test]
fn test_corrupted_config_no_panic() {
    // Create a corrupted config file
    let mut temp_config = NamedTempFile::new().unwrap();
    writeln!(temp_config, "this is {{ not valid toml").unwrap();

    let mut cmd = Command::cargo_bin("caut").unwrap();
    let output = cmd.arg("usage")
        .env("CAUT_CONFIG", temp_config.path())
        .output()
        .unwrap();

    // Should not contain panic
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(!stderr.to_lowercase().contains("panic"),
        "Should not panic on corrupted config");
}

#[test]
fn test_empty_output_json_valid() {
    // Even with no data, JSON should be valid
    let mut cmd = Command::cargo_bin("caut").unwrap();
    let output = cmd.arg("usage")
        .arg("--json")
        .output()
        .unwrap();

    // Should always produce valid JSON (even if data is empty)
    let _: serde_json::Value = serde_json::from_slice(&output.stdout)
        .expect("Output should always be valid JSON");
}
